local PhysicalConvoyController = (function()
local PhysicalConvoyController = {}

local STATE_NOT_SPAWNED = "NOT_SPAWNED"
local STATE_SPAWNING = "SPAWNING"
local STATE_SPAWNED = "SPAWNED"
local STATE_SPAWN_FAILED = "SPAWN_FAILED"
local STATE_DESTROYED = "DESTROYED"

local function displayValue(value)
  if value == nil then
    return "none"
  end
  return tostring(value)
end

function PhysicalConvoyController.new(options)
  local config = options.config
  local logger = options.logger
  local convoy = {
    state = STATE_NOT_SPAWNED,
    spawner = nil,
    runtimeGroup = nil,
    runtimeGroupName = nil,
    currentUnitCount = nil,
    startZoneMembership = nil,
    spawnExecutionAttempted = false,
  }

  local function commonFields()
    return {
      entityId = config.scenarioId,
      templateName = config.template.groupName,
      requestedAlias = config.template.runtimeAlias,
      runtimeGroupName = convoy.runtimeGroupName or "none",
      startZoneName = config.zones.start,
      expectedUnitCount = config.template.expectedVehicleCount,
      convoyState = convoy.state,
    }
  end

  local function announce(text)
    options.announce(text)
  end

  local function logRejected(reason)
    local fields = commonFields()
    fields.reason = reason
    fields.missionTimeSeconds = timer.getTime()
    logger:info("convoy_spawn_rejected", fields)
    announce(
      "Convoy spawn rejected: " .. reason
        .. "\nState: " .. convoy.state
        .. "\nRuntime group: " .. displayValue(convoy.runtimeGroupName)
    )
  end

  local function logFailed(reason)
    local reasonText = tostring(reason)
    convoy.state = STATE_SPAWN_FAILED
    local fields = commonFields()
    fields.reason = reasonText
    fields.missionTimeSeconds = timer.getTime()
    logger:error("convoy_spawn_failed", fields)
    announce("Convoy spawn failed: " .. reasonText)
  end

  local function inspectRuntimeGroup(startZone, templateGroup)
    return pcall(function()
      return {
        runtimeGroupName = convoy.runtimeGroup:GetName(),
        alive = convoy.runtimeGroup:IsAlive() == true,
        unitCount = convoy.runtimeGroup:CountAliveUnits(),
        startZoneMembership = convoy.runtimeGroup:IsCompletelyInZone(startZone) == true,
        templateAlive = templateGroup:IsAlive() == true,
      }
    end)
  end

  local function refreshRuntimeStatus()
    if not convoy.runtimeGroup then
      return true, nil
    end

    local lookupOk, startZone, templateGroup = pcall(function()
      return ZONE:FindByName(config.zones.start), GROUP:FindByName(config.template.groupName)
    end)
    if not lookupOk then
      return false, startZone
    end

    if not startZone or not templateGroup then
      return false, "required group or zone wrapper is unavailable"
    end

    local inspectionOk, inspection = inspectRuntimeGroup(startZone, templateGroup)
    if not inspectionOk then
      return false, inspection
    end

    convoy.runtimeGroupName = inspection.runtimeGroupName or convoy.runtimeGroupName
    convoy.currentUnitCount = inspection.unitCount
    convoy.startZoneMembership = inspection.startZoneMembership

    if inspection.unitCount < 1
      and (convoy.state == STATE_SPAWNED or convoy.state == STATE_SPAWN_FAILED) then
      convoy.state = STATE_DESTROYED
    end

    return true, inspection
  end

  function convoy:requestSpawn()
    local requestedFields = commonFields()
    requestedFields.bootstrapOutcome = options.getBootstrapOutcome()
    requestedFields.missionTimeSeconds = timer.getTime()
    logger:info("convoy_spawn_requested", requestedFields)

    if options.getBootstrapOutcome() ~= "READY" then
      logRejected("bootstrap outcome is not READY")
      return
    end

    if self.state == STATE_SPAWNING then
      logRejected("spawn is already in progress")
      return
    end

    if self.runtimeGroup or self.spawnExecutionAttempted then
      local refreshOk, refreshResult = refreshRuntimeStatus()
      if not refreshOk then
        logger:error("convoy_status", {
          convoyState = self.state,
          entityId = config.scenarioId,
          inspectionError = refreshResult,
          runtimeGroupName = self.runtimeGroupName or "none",
        })
      end
      if refreshOk and refreshResult and refreshResult.alive then
        logRejected("live runtime group already exists")
      else
        logRejected("a convoy spawn has already been executed")
      end
      return
    end

    self.state = STATE_SPAWNING

    local preparationOk, preparation = pcall(function()
      local templateGroup = GROUP:FindByName(config.template.groupName)
      local startZone = ZONE:FindByName(config.zones.start)
      if not templateGroup then
        error("template wrapper is unavailable")
      end
      if not startZone then
        error("start zone wrapper is unavailable")
      end
      if templateGroup:IsAlive() == true then
        error("original Late Activation template is already active")
      end
      return {
        templateGroup = templateGroup,
        startZone = startZone,
      }
    end)
    if not preparationOk then
      logFailed(preparation)
      return
    end

    local constructionOk, spawnerOrError = pcall(function()
      return SPAWN:NewWithAlias(config.template.groupName, config.template.runtimeAlias)
    end)
    if not constructionOk or not spawnerOrError then
      logFailed(constructionOk and "SPAWN construction returned nil" or spawnerOrError)
      return
    end
    self.spawner = spawnerOrError

    self.spawnExecutionAttempted = true
    local spawnOk, groupOrError = pcall(function()
      return self.spawner:SpawnInZone(preparation.startZone, false)
    end)
    if not spawnOk or type(groupOrError) ~= "table" then
      logFailed(spawnOk and "SpawnInZone did not return a GROUP wrapper" or groupOrError)
      return
    end
    self.runtimeGroup = groupOrError

    local inspectionOk, inspection = inspectRuntimeGroup(
      preparation.startZone,
      preparation.templateGroup
    )
    if not inspectionOk then
      logFailed(inspection)
      return
    end

    self.runtimeGroupName = inspection.runtimeGroupName
    self.currentUnitCount = inspection.unitCount
    self.startZoneMembership = inspection.startZoneMembership

    local failures = {}
    if type(inspection.runtimeGroupName) ~= "string" or inspection.runtimeGroupName == "" then
      failures[#failures + 1] = "runtime group name is unavailable"
    elseif inspection.runtimeGroupName == config.template.groupName then
      failures[#failures + 1] = "runtime group reused the template name"
    elseif string.sub(inspection.runtimeGroupName, 1, #config.template.runtimeAlias)
      ~= config.template.runtimeAlias then
      failures[#failures + 1] = "runtime group name does not use the requested alias"
    end
    if not inspection.alive then
      failures[#failures + 1] = "runtime group is not alive"
    end
    if inspection.unitCount ~= config.template.expectedVehicleCount then
      failures[#failures + 1] = "runtime group unit count is not six"
    end
    if not inspection.startZoneMembership then
      failures[#failures + 1] = "runtime group is not completely inside the start zone"
    end
    if inspection.templateAlive then
      failures[#failures + 1] = "original template became active"
    end

    if #failures > 0 then
      logFailed(table.concat(failures, ", "))
      return
    end

    self.state = STATE_SPAWNED
    local successFields = commonFields()
    successFields.actualUnitCount = inspection.unitCount
    successFields.missionTimeSeconds = timer.getTime()
    successFields.startZoneMembership = inspection.startZoneMembership
    successFields.templateRemainsInactive = not inspection.templateAlive
    logger:info("convoy_spawn_succeeded", successFields)
    announce(
      "Convoy spawned\nRuntime group: " .. inspection.runtimeGroupName
        .. "\nUnits: " .. inspection.unitCount
        .. "\nState: " .. self.state
    )
  end

  function convoy:showStatus()
    local inspectionOk, inspectionError = refreshRuntimeStatus()
    local fields = commonFields()
    fields.currentUnitCount = self.currentUnitCount or "unavailable"
    fields.missionTimeSeconds = timer.getTime()
    fields.startZoneMembership = self.startZoneMembership == nil
      and "unavailable" or self.startZoneMembership
    if not inspectionOk then
      fields.inspectionError = inspectionError
    end
    logger:info("convoy_status", fields)

    announce(
      "Entity: " .. config.scenarioId
        .. "\nConvoy state: " .. self.state
        .. "\nRuntime group: " .. displayValue(self.runtimeGroupName)
        .. "\nExpected units: " .. config.template.expectedVehicleCount
        .. "\nCurrent units: " .. displayValue(self.currentUnitCount)
    )
  end

  function convoy:getRouteHandoff()
    local inspectionOk, inspectionError = refreshRuntimeStatus()
    return {
      inspectionOk = inspectionOk,
      inspectionError = inspectionError,
      state = self.state,
      runtimeGroup = self.runtimeGroup,
      runtimeGroupName = self.runtimeGroupName,
      currentUnitCount = self.currentUnitCount,
    }
  end

  function convoy:markDestroyed()
    if self.runtimeGroup then
      self.state = STATE_DESTROYED
    end
  end

  return convoy
end

return PhysicalConvoyController
end)()

local ConvoyRouteController = (function()
local ConvoyRouteController = {}

local STATE_NOT_READY = "NOT_READY"
local STATE_READY = "READY"
local STATE_STARTING = "STARTING"
local STATE_EN_ROUTE = "EN_ROUTE"
local STATE_ARRIVED = "ARRIVED"
local STATE_ROUTE_FAILED = "ROUTE_FAILED"
local STATE_DESTROYED = "DESTROYED"

local MOOSE_FORMATIONS = {
  ON_ROAD = "On Road",
}

local function displayValue(value)
  if value == nil then
    return "none"
  end
  return tostring(value)
end

function ConvoyRouteController.new(options)
  local config = options.config
  local logger = options.logger
  local route = {
    state = STATE_NOT_READY,
    routeAssignmentAttempted = false,
    routeAssigned = false,
    runtimeGroupName = nil,
    currentUnitCount = nil,
    targetZoneMembership = nil,
    waypointCount = 0,
    arrivalLogged = false,
  }

  local function commonFields()
    return {
      entityId = config.scenarioId,
      routeId = config.routeId,
      routeState = route.state,
      runtimeGroupName = route.runtimeGroupName or "none",
      configuredSpeedKph = config.routing.speedKph,
      formation = config.routing.formation,
      roadOnly = config.routing.roadOnly,
      routeAssigned = route.routeAssigned,
    }
  end

  local function announce(text)
    options.announce(text)
  end

  local function logRejected(reason)
    local fields = commonFields()
    fields.reason = reason
    fields.missionTimeSeconds = timer.getTime()
    logger:info("convoy_route_rejected", fields)
    announce(
      "Convoy route rejected: " .. reason
        .. "\nRoute state: " .. route.state
        .. "\nRuntime group: " .. displayValue(route.runtimeGroupName)
    )
  end

  local function logFailed(reason)
    local reasonText = tostring(reason)
    route.state = STATE_ROUTE_FAILED
    local fields = commonFields()
    fields.reason = reasonText
    fields.missionTimeSeconds = timer.getTime()
    logger:error("convoy_route_failed", fields)
    announce("Convoy route failed: " .. reasonText)
  end

  local function getPhysicalSnapshot()
    local ok, snapshot = pcall(function()
      return options.physicalConvoyController:getRouteHandoff()
    end)
    if not ok then
      return false, snapshot
    end
    if type(snapshot) ~= "table" then
      return false, "physical convoy handoff is unavailable"
    end
    if not snapshot.inspectionOk then
      return false, snapshot.inspectionError or "physical convoy inspection failed"
    end
    return true, snapshot
  end

  local function inspectRuntimeGroup(snapshot, targetZone)
    return pcall(function()
      local group = snapshot.runtimeGroup
      if type(group) ~= "table" then
        error("runtime group wrapper is unavailable")
      end
      local targetZoneMembership = nil
      if targetZone then
        targetZoneMembership = group:IsCompletelyInZone(targetZone) == true
      end
      return {
        actualRuntimeGroupName = group:GetName(),
        alive = group:IsAlive() == true,
        livingUnitCount = group:CountAliveUnits(),
        targetZoneMembership = targetZoneMembership,
      }
    end)
  end

  local function evaluateReadiness()
    local snapshotOk, snapshot = getPhysicalSnapshot()
    if not snapshotOk then
      return false, snapshot
    end

    route.runtimeGroupName = snapshot.runtimeGroupName
    route.currentUnitCount = snapshot.currentUnitCount

    if snapshot.state == "DESTROYED" then
      route.state = STATE_DESTROYED
      return false, "physical convoy is destroyed"
    end
    if snapshot.state == "NOT_SPAWNED" then
      route.state = STATE_NOT_READY
      return false, "physical convoy has not been spawned"
    end
    if snapshot.state == "SPAWNING" then
      route.state = STATE_NOT_READY
      return false, "physical convoy is still spawning"
    end
    if snapshot.state == "SPAWN_FAILED" then
      route.state = STATE_NOT_READY
      return false, "physical convoy spawn failed"
    end
    if snapshot.state ~= "SPAWNED" then
      route.state = STATE_NOT_READY
      return false, "physical convoy is not ready"
    end
    if options.getBootstrapOutcome() ~= "READY" then
      route.state = STATE_NOT_READY
      return false, "bootstrap outcome is not READY"
    end
    if type(snapshot.runtimeGroup) ~= "table" then
      route.state = STATE_NOT_READY
      return false, "runtime group wrapper is unavailable"
    end

    local inspectionOk, inspection = inspectRuntimeGroup(snapshot, nil)
    if not inspectionOk then
      return false, inspection
    end
    route.runtimeGroupName = inspection.actualRuntimeGroupName or route.runtimeGroupName
    route.currentUnitCount = inspection.livingUnitCount

    if inspection.livingUnitCount < 1 then
      route.state = STATE_DESTROYED
      options.physicalConvoyController:markDestroyed()
      return false, "runtime group has no living units"
    end
    if not inspection.alive and not route.routeAssigned then
      route.state = STATE_NOT_READY
      return false, "runtime group is not alive"
    end
    if type(snapshot.runtimeGroupName) ~= "string"
      or inspection.actualRuntimeGroupName ~= snapshot.runtimeGroupName then
      route.state = STATE_NOT_READY
      return false, "actual runtime group name does not match tracked group"
    end
    if inspection.actualRuntimeGroupName == config.template.groupName then
      route.state = STATE_NOT_READY
      return false, "refusing to route the original template"
    end

    if route.state == STATE_NOT_READY or route.state == STATE_READY then
      route.state = STATE_READY
    end
    return true, {
      snapshot = snapshot,
      inspection = inspection,
    }
  end

  local function buildDeterministicRoute()
    return pcall(function()
      local routeZoneNames = {}
      for index, zoneName in ipairs(config.zones.routeAnchors) do
        routeZoneNames[index] = zoneName
      end
      routeZoneNames[#routeZoneNames + 1] = config.zones.target

      local formation = MOOSE_FORMATIONS[config.routing.formation]
      if config.routing.roadOnly ~= true or not formation then
        error("road-only ON_ROAD routing configuration is required")
      end

      local waypoints = {}
      local zones = {}
      for index, zoneName in ipairs(routeZoneNames) do
        local zone = ZONE:FindByName(zoneName)
        if not zone then
          error("route zone is unavailable: " .. zoneName)
        end
        local coordinate = zone:GetCoordinate()
        if not coordinate then
          error("route-zone coordinate is unavailable: " .. zoneName)
        end
        local waypoint = coordinate:WaypointGround(config.routing.speedKph, formation)
        if type(waypoint) ~= "table" then
          error("ground waypoint construction failed: " .. zoneName)
        end
        zones[index] = zone
        waypoints[index] = waypoint
      end

      if #waypoints ~= #config.zones.routeAnchors + 1 then
        error("route waypoint count is incomplete")
      end

      return {
        waypoints = waypoints,
        targetZone = zones[#zones],
        firstRouteZoneName = routeZoneNames[1],
        finalTargetZoneName = routeZoneNames[#routeZoneNames],
      }
    end)
  end

  function route:start()
    local requestedFields = commonFields()
    requestedFields.missionTimeSeconds = timer.getTime()
    logger:info("convoy_route_requested", requestedFields)

    if self.state == STATE_STARTING or self.state == STATE_EN_ROUTE then
      logRejected("route has already started")
      return
    end
    if self.state == STATE_ARRIVED then
      logRejected("route has already arrived")
      return
    end
    if self.state == STATE_ROUTE_FAILED then
      logRejected("route assignment previously failed")
      return
    end
    if self.state == STATE_DESTROYED then
      logRejected("physical convoy is destroyed")
      return
    end
    if self.routeAssignmentAttempted or self.routeAssigned then
      logRejected("route assignment has already been attempted")
      return
    end

    local readinessOk, readiness = evaluateReadiness()
    if not readinessOk then
      logRejected(readiness)
      return
    end

    self.state = STATE_STARTING
    local constructionOk, routeDefinition = buildDeterministicRoute()
    if not constructionOk then
      logFailed(routeDefinition)
      return
    end

    local runtimeGroup = readiness.snapshot.runtimeGroup
    self.routeAssignmentAttempted = true
    local assignmentOk, assignmentResult = pcall(function()
      return runtimeGroup:Route(routeDefinition.waypoints, 0)
    end)
    if not assignmentOk or not assignmentResult then
      logFailed(assignmentOk and "route assignment returned nil" or assignmentResult)
      return
    end

    self.routeAssigned = true
    self.waypointCount = #routeDefinition.waypoints
    self.state = STATE_EN_ROUTE

    local fields = commonFields()
    fields.anchorCount = #config.zones.routeAnchors
    fields.totalWaypointCount = self.waypointCount
    fields.firstRouteZoneName = routeDefinition.firstRouteZoneName
    fields.finalTargetZoneName = routeDefinition.finalTargetZoneName
    fields.missionTimeSeconds = timer.getTime()
    logger:info("convoy_route_started", fields)
    announce(
      "Convoy route started"
        .. "\nRuntime group: " .. self.runtimeGroupName
        .. "\nWaypoints: " .. self.waypointCount
        .. "\nSpeed: " .. config.routing.speedKph .. " km/h"
    )
  end

  function route:showStatus()
    local readinessOk, readiness = evaluateReadiness()
    local targetZone = nil

    local targetLookupOk, targetOrError = pcall(function()
      return ZONE:FindByName(config.zones.target)
    end)
    if targetLookupOk then
      targetZone = targetOrError
    end

    if readinessOk and targetZone then
      local inspectionOk, inspection = inspectRuntimeGroup(readiness.snapshot, targetZone)
      if inspectionOk then
        self.runtimeGroupName = inspection.actualRuntimeGroupName or self.runtimeGroupName
        self.currentUnitCount = inspection.livingUnitCount
        self.targetZoneMembership = inspection.targetZoneMembership

        if inspection.livingUnitCount < 1 then
          self.state = STATE_DESTROYED
          options.physicalConvoyController:markDestroyed()
        elseif self.routeAssigned and inspection.targetZoneMembership then
          self.state = STATE_ARRIVED
          if not self.arrivalLogged then
            self.arrivalLogged = true
            local arrivalFields = commonFields()
            arrivalFields.livingUnitCount = inspection.livingUnitCount
            arrivalFields.missionTimeSeconds = timer.getTime()
            arrivalFields.targetZoneName = config.zones.target
            arrivalFields.targetZoneMembership = true
            logger:info("convoy_route_arrived", arrivalFields)
          end
        end
      else
        readinessOk = false
        readiness = inspection
      end
    elseif not targetLookupOk then
      readinessOk = false
      readiness = targetOrError
    elseif not targetZone then
      readinessOk = false
      readiness = "target zone is unavailable"
    end

    local fields = commonFields()
    fields.currentLivingUnitCount = self.currentUnitCount or "unavailable"
    fields.missionTimeSeconds = timer.getTime()
    fields.targetZoneMembership = self.targetZoneMembership == nil
      and "unavailable" or self.targetZoneMembership
    fields.totalWaypointCount = self.waypointCount
    if not readinessOk then
      fields.inspectionError = readiness
    end
    logger:info("convoy_route_status", fields)

    announce(
      "Entity: " .. config.scenarioId
        .. "\nRoute: " .. config.routeId
        .. "\nRoute state: " .. self.state
        .. "\nRuntime group: " .. displayValue(self.runtimeGroupName)
        .. "\nSpeed: " .. config.routing.speedKph .. " km/h"
        .. "\nLiving units: " .. displayValue(self.currentUnitCount)
        .. "\nInside target: " .. displayValue(self.targetZoneMembership)
        .. "\nRoute assigned: " .. tostring(self.routeAssigned)
    )
  end

  return route
end

return ConvoyRouteController
end)()

local TM01A = (function()
local TM01A = {}

local OUTCOME_READY = "READY"
local OUTCOME_FAIL_CONFIGURATION = "FAIL_CONFIGURATION"
local OUTCOME_FAIL_SCRIPT = "FAIL_SCRIPT"

local function join(values)
  if #values == 0 then
    return "none"
  end

  return table.concat(values, ",")
end

function TM01A.start(dependencies)
  local build = dependencies.build
  local config = dependencies.config
  local state = {
    outcome = OUTCOME_FAIL_SCRIPT,
    detail = "bootstrap not completed",
    checkedObjectCount = 0,
  }

  local nativeValid, missingNativeApis = dependencies.runtimeGuard.validateNative()
  if not nativeValid then
    state.detail = "required native DCS APIs are unavailable"
    dependencies.safeReporter.report(
      "native_api_validation_failed",
      OUTCOME_FAIL_SCRIPT,
      "missing=" .. join(missingNativeApis)
    )
    return state
  end

  local logger = dependencies.structuredLogger.new("[OMW][TM01A]")

  local function announce(text)
    trigger.action.outText("[OMW][TM01A] " .. text, 15, false)
  end

  local function setOutcome(outcome, detail)
    state.outcome = outcome
    state.detail = detail
    logger:info("bootstrap_outcome", {
      detail = detail,
      outcome = outcome,
    })
  end

  local function validateConfiguration()
    local ok, result = pcall(dependencies.configurationValidator.validate, config)

    if not ok then
      setOutcome(OUTCOME_FAIL_SCRIPT, "configuration validation raised an error")
      logger:error("configuration_validation_error", { error = result })
      return
    end

    state.checkedObjectCount = result.checkedObjectCount

    if #result.errors > 0 then
      setOutcome(OUTCOME_FAIL_SCRIPT, "Mission Editor object lookup failed")
      logger:error("configuration_lookup_error", { errors = join(result.errors) })
      return
    end

    if not result.valid then
      setOutcome(OUTCOME_FAIL_CONFIGURATION, "required Mission Editor objects are missing")
      logger:error("configuration_invalid", {
        checkedObjectCount = result.checkedObjectCount,
        missing = join(result.missing),
      })
      return
    end

    logger:info("configuration_valid", {
      checkedObjectCount = result.checkedObjectCount,
      revealZonesRequired = false,
    })
    setOutcome(OUTCOME_READY, "bootstrap validation completed")
  end

  local function showStatus()
    local text = "Outcome: " .. state.outcome .. "\nDetail: " .. state.detail
    logger:info("status_requested", {
      checkedObjectCount = state.checkedObjectCount,
      detail = state.detail,
      outcome = state.outcome,
    })
    announce(text)
  end

  local function validateFromMenu()
    validateConfiguration()
    showStatus()
  end

  local function protectMenuCallback(commandName, callback)
    return function()
      local ok, callbackError = pcall(callback)
      if not ok then
        logger:error("menu_callback_failed", {
          command = commandName,
          error = callbackError,
          outcome = OUTCOME_FAIL_SCRIPT,
        })
        announce("Menu command failed: " .. commandName)
      end
    end
  end

  logger:info("startup", {
    buildTimestamp = build.buildTimestamp,
    configurationVersion = build.configurationVersion,
    dcsVersion = tostring(_G.DCS_VERSION or _G._DCS_VERSION or "unavailable"),
    expectedMooseBuildCommit = build.expectedMooseBuildCommit,
    expectedMooseBuildTimestamp = build.expectedMooseBuildTimestamp,
    expectedMooseCompression = build.expectedMooseCompression,
    expectedMooseFileSha256 = build.expectedMooseFileSha256,
    expectedMooseIncludeFamily = build.expectedMooseIncludeFamily,
    expectedMooseVersion = build.expectedMooseVersion,
    missionTimeSeconds = timer.getTime(),
    mooseVerificationMode = build.mooseVerificationMode,
    stageId = build.stageId,
    testId = build.testId,
  })

  logger:info("native_api_validation_passed", { nativeApiCount = 3 })

  local mooseValid, missingMooseApis = dependencies.runtimeGuard.validateMoose()
  if not mooseValid then
    setOutcome(OUTCOME_FAIL_SCRIPT, "required MOOSE APIs are unavailable")
    logger:error("moose_api_validation_failed", { missing = join(missingMooseApis) })
    return state
  end

  logger:info("moose_api_validation_passed", {
    mooseApiCount = 13,
  })

  local convoyController = dependencies.physicalConvoyController.new({
    announce = announce,
    config = config,
    getBootstrapOutcome = function()
      return state.outcome
    end,
    logger = logger,
  })

  local routeController = dependencies.convoyRouteController.new({
    announce = announce,
    config = config,
    getBootstrapOutcome = function()
      return state.outcome
    end,
    logger = logger,
    physicalConvoyController = convoyController,
  })

  local menuOk, menuOrError = pcall(dependencies.testMenu.create, {
    stageId = build.stageId,
    onShowStatus = protectMenuCallback("Show status", showStatus),
    onValidateConfiguration = protectMenuCallback(
      "Validate configuration",
      validateFromMenu
    ),
    onSpawnConvoy = protectMenuCallback("Spawn convoy", function()
      convoyController:requestSpawn()
    end),
    onShowConvoyStatus = protectMenuCallback("Show convoy status", function()
      convoyController:showStatus()
    end),
    onStartConvoyRoute = protectMenuCallback("Start convoy route", function()
      routeController:start()
    end),
    onShowRouteStatus = protectMenuCallback("Show route status", function()
      routeController:showStatus()
    end),
  })

  if not menuOk then
    setOutcome(OUTCOME_FAIL_SCRIPT, "F10 menu creation failed")
    logger:error("menu_creation_failed", { error = menuOrError })
    return state
  end

  state.menu = menuOrError
  state.convoyController = convoyController
  state.routeController = routeController
  logger:info("menu_ready", { path = "OMW Tests / " .. build.stageId })
  validateConfiguration()

  return state
end

return TM01A
end)()

local entryOk, entryResult = pcall(function()
  return TM01A.start({
    build = OMWBuild,
    config = TM01Config,
    safeReporter = SafeReporter,
    structuredLogger = StructuredLogger,
    runtimeGuard = RuntimeGuard,
    configurationValidator = ConfigurationValidator,
    testMenu = TestMenu,
    physicalConvoyController = PhysicalConvoyController,
    convoyRouteController = ConvoyRouteController,
  })
end)

local TM01AState = entryResult
if not entryOk then
  SafeReporter.report("bootstrap_uncaught_error", "FAIL_SCRIPT", entryResult)
  TM01AState = {
    outcome = "FAIL_SCRIPT",
    detail = "bootstrap raised an uncaught error",
  }
end
